7.1.1 题目编写一个程序，不断要求用户输入两个数，直到其中的一个为0。对于每两个数，程序将使用一个函数来计算它们的调和平均数，并将结果返回给 main()，而后者将报告结果。调和平均数指的是倒数平均值的倒数，计算公式如下：1调和平均数 = 2.0*x*y/(x+y) 7.1.2 代码12345678910111213141516171819202122232425#include &lt;iostream&gt;double har_ave(double x, double y);int main()&#123; using namespace std; double n,m; cout &lt;&lt; &quot;Enter double nums(0 to quit): &quot;; cin &gt;&gt; n &gt;&gt; m; while((n!=0)&amp;&amp;(m!=0)) &#123; cout &lt;&lt; &quot;The answer is: &quot; &lt;&lt; har_ave(n,m) &lt;&lt; endl; cout &lt;&lt; &quot;Enter double nums(0 to quit): &quot;; cin &gt;&gt; n &gt;&gt; m; &#125; cout &lt;&lt; &quot;Has the 0, quit&quot; &lt;&lt; endl; return 0;&#125;double har_ave(double x, double y)&#123; double ave = 2.0*x*y/(x+y); return ave;&#125; 7.1.3 运行结果12345678910PS E:\Buffer\C++_code&gt; g++ .	est.cpp -o test.exePS E:\Buffer\C++_code&gt; .	est.exeEnter double nums(0 to quit): 2 2The answer is: 2Enter double nums(0 to quit): 1 2The answer is: 1.33333Enter double nums(0 to quit): 2.2 2.2The answer is: 2.2Enter double nums(0 to quit): 0 1Has the 0, quit 7.2 略 7.3.1 题目下面是一个结构声明：12345678struct box &#123; char maker[40]; float height; float width; float length; float volume; &#125;; a. 编写一个函数，按值传递 box 的结构，并显示每个成员的值。b. 编写一个函数，传递 box 结构的地址，并将 volume 成员设置为其他三维长度的乘积。c. 编写一个使用这两个函数的简单程序。 7.3.2 代码12345678910111213141516171819202122232425262728293031323334353637#include &lt;iostream&gt;using namespace std;struct box&#123; char maker[40]; float height; float width; float length; float volume;&#125;;void value_return(box value);void addr_return(box * addr);int main()&#123; box box_test = &#123;&quot;chen&quot;, 1.1, 2.0, 1.1, 0.0&#125;; value_return(box_test); addr_return(&amp;box_test); value_return(box_test); return 0;&#125;void value_return(box value)&#123; cout &lt;&lt; &quot;***** This is value return: *****&quot; &lt;&lt; endl; cout &lt;&lt; &quot;maker: &quot; &lt;&lt; value.maker &lt;&lt; endl; cout &lt;&lt; &quot;height: &quot; &lt;&lt; value.height &lt;&lt; endl; cout &lt;&lt; &quot;width: &quot; &lt;&lt; value.width &lt;&lt; endl; cout &lt;&lt; &quot;length: &quot; &lt;&lt; value.length &lt;&lt; endl; cout &lt;&lt; &quot;volume: &quot; &lt;&lt; value.volume &lt;&lt; endl;&#125;void addr_return(box * addr)&#123; addr-&gt;volume = addr-&gt;height*addr-&gt;width*addr-&gt;length;&#125; 7.3.3 运行结果12345678910111213PS E:\Buffer\C++_code&gt; .	est.exe***** This is value return: *****maker: chenheight: 1.1width: 2length: 1.1volume: 0***** This is value return: *****maker: chenheight: 1.1width: 2length: 1.1volume: 2.42 7.4 略 7.5.1 题目定义一个递归函数，接受一个整数参数，并返回该参数的阶乘。前面讲过，3 的阶乘写作 3！，等于 3*2！，依此类推；而 0！被定义为1.通用的计算公式是，如果 n 大于 0，则1n!=n*(n-1) 在程序中对该函数进行测试，程序使用循环让用户输入不同的值，程序将报告这些值的阶乘。 7.5.2 代码1234567891011121314151617181920212223#include &lt;iostream&gt;long factorial(int n);int main()&#123; using namespace std; int x; cout &lt;&lt; &quot;Enter the num: &quot;; while(cin&gt;&gt;x) &#123; cout &lt;&lt; x &lt;&lt; &quot;! is &quot; &lt;&lt; factorial(x) &lt;&lt; endl; cout &lt;&lt; &quot;Enter the num: &quot;; &#125; return 0;&#125;long factorial(int n)&#123; if (n==0) return 1; else return n*factorial(n-1);&#125; 7.5.3 运行结果123456789101112PS E:\Buffer\C++_code&gt; .	est.exeEnter the num: 00! is 1Enter the num: 11! is 1Enter the num: 22! is 2Enter the num: 33! is 6Enter the num: 44! is 24Enter the num: q 7.6.1 题目编写一个程序，它将使用下列函数：Fill_array() 将一个 double 数组的名称和长度作为参数。它提示用户输入 double 值，并将这些值存储到数组中。当数组被填满或用户输入了非数字时，输入将停止，并返回实际输入了多少个数字。Show_array() 将一个 double 数组的名称和长度作为参数，并显示该数组的内容。Reverse_array() 将一个 double 数组的名称和长度作为参数，并将存储在数组中的值的顺序反转。程序将使用这些函数来填充数组，然后显示数组；反转数组，然后显示数组；反转数组中除第一个和最后一个元素之外的所有元素，然后显示数组。 7.6.2 代码1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556#include &lt;iostream&gt;using namespace std;const int len = 4;int Fill_array(double str[], int size);void Show_array(double str[], int n);void Reverse_array(double str[], int n);int main()&#123; double strs[len] = &#123;0.0&#125;; int real_size; real_size = Fill_array(strs, len); Show_array(strs, real_size+1); Reverse_array(strs, real_size+1); Show_array(strs, real_size+1); return 0;&#125;;int Fill_array(double str[], int size)&#123; double value; int num=0; for (int i=0; i&lt;size; ++i) &#123; cout &lt;&lt; &quot;Enter the value(double): &quot;; if(!(cin&gt;&gt;value)) &#123; cin.clear(); while (cin.get() != &apos;
&apos;) continue; cout &lt;&lt; &quot;Bad input; Please enter a number: &quot;; break; &#125; else str[num++] = value; &#125; return num-1;&#125;void Show_array(double str[], int n)&#123; for (int i=0; i&lt;n; ++i) cout &lt;&lt; str[i] &lt;&lt; &quot; &quot; &lt;&lt; endl;&#125;void Reverse_array(double str[], int n)&#123; for (int i=0; i&lt;n/2; ++i) &#123; double temp = str[i]; str[i] = str[n-i-1]; str[n-i-1] = temp; &#125; &#125; 7.6.3 运行结果12345678910111213141516171819PS E:\Buffer\C++_code&gt; .	est.exeEnter the value(double): 1.1Enter the value(double): cBad input; Please enter a number: 1.11.1PS E:\Buffer\C++_code&gt; .	est.exeEnter the value(double): 1.1Enter the value(double): 2.2Enter the value(double): 3.3Enter the value(double): 4.41.12.23.34.44.43.32.21.1 7.7.1 题目修改程序清单 7.7 中的 3 个数组处理函数，使之使用两个指针参数来表示区间。fill_array() 函数不返回实际读取了多少个数字，而是返回一个指针，该指针指向最后被填充的位置；其他的函数可以将该指针作为第二个参数，以标识数据结尾。 7.7.2 代码1234567891011121314151617int main()&#123; using namespace std; const int Max=5; double arr[Max]; int * arr_end = fill_array(arr, Max); show_array(arr, arr_end); if (arr_end != arr) &#123; ... revalue(factor, arr, arr_end); show(arr, arr_end); &#125; return 0;&#125; 7.8.1 题目在不使用 array 类的情况下完成程序清单 7.15 所做的工作。编写两个这样的版本：a. 使用 const char 数组存储表示季度名称的字符串，并使用 double 数组存储开支。b. 使用 const char 数组存储表示季度名称的字符串，并使用一个结构，该结构只有一个成员——一个用于存储开支的 double 数组。这种设计与使用 array 类的基本设计类似。 7.8.2 代码12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576777879808182a#include &lt;iostream&gt;using namespace std;const int Seasons = 4;const char* Snames[Seasons] = &#123;&quot;Spring&quot;, &quot;Summer&quot;, &quot;Fall&quot;, &quot;Winter&quot;&#125;;void fill(double* array);void show(double *array);int main()&#123; double expenses[Seasons]; fill(expenses); show(expenses); return 0;&#125;void fill(double *array)&#123; for (int i=0; i&lt;Seasons; i++) &#123; cout &lt;&lt; &quot;Enter &quot; &lt;&lt; Snames[i] &lt;&lt; &quot;expenses: &quot;; cin &gt;&gt; array[i]; &#125;&#125;void show(double *array)&#123; double total = 0.0; cout &lt;&lt; &quot;
EXPENSES
&quot;; for (int i=0; i&lt;Seasons; i++) &#123; cout &lt;&lt; Snames[i] &lt;&lt; &quot;: $&quot; &lt;&lt; array[i] &lt;&lt;endl; total += array[i]; &#125; cout &lt;&lt; &quot;Total expenses: $&quot; &lt;&lt; total &lt;&lt; endl;&#125;b#include &lt;iostream&gt;using namespace std;const int Seasons = 4;const char* Snames[Seasons] = &#123;&quot;Spring&quot;, &quot;Summer&quot;, &quot;Fall&quot;, &quot;Winter&quot;&#125;;struct dollar&#123; double expenses[Seasons];&#125;;void fill(dollar * array);void show(dollar * array);int main()&#123; dollar pay; fill(&amp;pay); show(&amp;pay); return 0;&#125;void fill(dollar *array)&#123; for (int i=0; i&lt;Seasons; i++) &#123; cout &lt;&lt; &quot;Enter &quot; &lt;&lt; Snames[i] &lt;&lt; &quot;expenses: &quot;; cin &gt;&gt; array-&gt;expenses[i]; &#125;&#125;void show(dollar *array)&#123; double total = 0.0; cout &lt;&lt; &quot;
EXPENSES
&quot;; for (int i=0; i&lt;Seasons; i++) &#123; cout &lt;&lt; Snames[i] &lt;&lt; &quot;: $&quot; &lt;&lt; array-&gt;expenses[i] &lt;&lt;endl; total += array-&gt;expenses[i]; &#125; cout &lt;&lt; &quot;Total expenses: $&quot; &lt;&lt; total &lt;&lt; endl;&#125; 7.8.3 运行结果1234567891011121314a bEnter Summerexpenses: PS E:\Buffer\C++_code&gt; .	est.exeEnter Springexpenses: 212Enter Summerexpenses: 256Enter Fallexpenses: 208Enter Winterexpenses: 244EXPENSESSpring: $212Summer: $256Fall: $208Winter: $244Total expenses: $920 7.9.1 题目太长了，，加油！ 7.9.2 代码12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576#include &lt;iostream&gt;#include &lt;cstring&gt;using namespace std;const int SLEN = 30;struct student&#123; char fullname[SLEN]; char hobby[SLEN]; int ooplevel;&#125;;int getinfo(student pa[], int n)&#123; int real_num=0; for(int i=0; i&lt;n; i++) &#123; cout &lt;&lt; &quot;Enter the student&apos;s name: &quot;; cin.getline(pa[i].fullname, SLEN); // if string type, getline(cin, pa[i].fullname) if(!strlen(pa[i].fullname)) break; cout &lt;&lt; &quot;Enter the student&apos;s hobby: &quot;; cin.getline(pa[i].hobby, SLEN); cout &lt;&lt; &quot;Enter the student&apos;s ooplevel: &quot;; (cin &gt;&gt; pa[i].ooplevel).get(); real_num++; &#125; return real_num;&#125;void display1(student st)&#123; cout &lt;&lt; &quot;name: &quot; &lt;&lt; st.fullname &lt;&lt; endl; cout &lt;&lt; &quot;hobby: &quot; &lt;&lt; st.hobby &lt;&lt; endl; cout &lt;&lt; &quot;ooplevel: &quot; &lt;&lt; st.ooplevel &lt;&lt; endl; &#125;void display2(const student *st)&#123; cout &lt;&lt; &quot;name: &quot; &lt;&lt; st-&gt;fullname &lt;&lt; endl; cout &lt;&lt; &quot;hobby: &quot; &lt;&lt; st-&gt;hobby &lt;&lt; endl; cout &lt;&lt; &quot;ooplevel: &quot; &lt;&lt; st-&gt;ooplevel &lt;&lt; endl;&#125;void display3(const student pa[],int n)&#123; for(int i = 0; i &lt; n; i++) &#123; cout &lt;&lt; &quot;info #&quot; &lt;&lt; i &lt;&lt; endl; cout &lt;&lt; &quot;name: &quot; &lt;&lt; (pa + i)-&gt;fullname &lt;&lt; endl; cout &lt;&lt; &quot;hobby: &quot; &lt;&lt; (pa + i)-&gt;hobby &lt;&lt; endl; cout &lt;&lt; &quot;ooplevel: &quot; &lt;&lt; (pa + i)-&gt;ooplevel &lt;&lt; endl; &#125;&#125;int main()&#123; cout &lt;&lt; &quot;enter class size: &quot;; int class_size; cin &gt;&gt; class_size; while(cin.get()!=&apos;
&apos;) continue; student *ptr_stu = new student[class_size]; int entered = getinfo(ptr_stu,class_size); cout &lt;&lt; &quot;
 diplay1 and 2 
&quot;; for(int i=0;i&lt;entered;i++) &#123; display1(ptr_stu[i]); display2(&amp;ptr_stu[i]); &#125; cout &lt;&lt; &quot;

&quot;; display3(ptr_stu,entered); delete [] ptr_stu; cout &lt;&lt; &quot;Done!&quot;; return 0;&#125; 7.9.3 运行结果12345678910111213141516171819202122232425262728PS E:\Buffer\C++_code&gt; .	est.exeenter class size: 1Enter the student&apos;s name: diplay1 and 2Done!PS E:\Buffer\C++_code&gt; .	est.exeenter class size: 1Enter the student&apos;s name: jac kEnter the student&apos;s hobby: pla yEnter the student&apos;s ooplevel: 12 diplay1 and 2name: jac khobby: pla yooplevel: 12name: jac khobby: pla yooplevel: 12info #0name: jac khobby: pla yooplevel: 12Done! 7.10.1 题目设计一个名为 calculate() 的函数，它接受两个 double 值和一个指向函数的指针，而被指向的函数接受两个 double 参数，并返回一个 double 值。calculate() 函数的类型也是 double，并返回被指向的函数使用 calculate() 的两个 double 参数计算得到的值。例如，假设 add() 函数的定义如下：1234double add(double x, double y)&#123; return x + y;&#125; 则用下述代码中的函数调用将导致 calculate() 把 2.5 和 10.4 传递给 add() 函数，并返回 add() 的返回值 (12.9):1double q = calculate(2.5, 10.4, add); 请编写一个程序，它调用上述两个函数和至少另一个与 add() 类似的函数。该程序使用循环来让用户成对的输入数字。对于每对数字，程序都使用 calculate() 来调用 add() 和至少一个其他的函数。如果读者爱冒险，可以尝试创建一个指针数组，其中的指针指向 add() 样式的函数，并编写一个循环，使用这些指针连续让 calculate() 调用这些函数。提示：下面是声明这种指针数组的方式，其中包含三个指针：1double (*pf[3])(double, double)； 可以采用数组初始化语法，并将函数名作为地址来初始化这样的数组。 7.10.2 代码1234567891011121314151617181920212223242526272829303132333435363738#include &lt;iostream&gt;double calculate(double x, double y, double (*pt)(double, double));double add(double x, double y);double reduce(double x, double y);int main()&#123; using namespace std; cout &lt;&lt; &quot;Enter two nums: &quot; &lt;&lt; endl; double n,m; cin &gt;&gt; n &gt;&gt; m; cout &lt;&lt; &quot;add value: &quot; &lt;&lt; calculate(n, m, add) &lt;&lt; endl; cout &lt;&lt; &quot;reduce value: &quot; &lt;&lt; calculate(n, m, reduce) &lt;&lt; endl; double (*pf[2])(double, double) = &#123;add, reduce&#125;; // 函数指针数组 cout &lt;&lt; &quot;an array of 2 function pointers: &quot; &lt;&lt; endl; for (int i=0; i&lt;2; i++) &#123; cout &lt;&lt; calculate(n, m, pf[i]) &lt;&lt; endl; &#125; return 0;&#125;double calculate(double x, double y, double (*pt)(double, double))&#123; return pt(x, y);&#125;double add(double x, double y)&#123; return x+y;&#125;double reduce(double x, double y)&#123; return x-y;&#125; 7.10.3 运行结果12345678PS E:\Buffer\C++_code&gt; .	est.exeEnter two nums:1.1 2.2add value: 3.3reduce value: -1.1an array of 2 function pointers:3.3-1.1

基于FPGA的任意波形发生器（Easy版）【2017.04.13】Chenyu 实现功能： 要求用FPGA做一款波形、幅值、频率可调，且频率可通过开发板的数码管显示硬件平台： Altera 黑金 AX301 Cyclone ⅣE EP4CE6F17C8 R-2R电阻网络（DAC模块）软件平台： QuartusⅡ Guagle/matlab 思路： 用C或者matlab等软件生成mif文件；将mif文件导入FPGA的ROM；对各个模块编写程序；模块例化5.DAC 一、生成MIF文件mif文件就是存储器初始化文件，即memory initialization file，用来配置RAM或ROM中的数据。 1.1 利用Quartus自带的mif编译器优：对小容量的RAM、ROM可以快速方便的完成mif文件的编辑工作，不需要第三方软件编辑；缺：数据量过大时，不推荐使用使用方法：【File】_&gt;【New】 _&gt;【Memory Initialization file】 Number of words：可寻址的存储单元数，对于8bit地址线，此处选择256；words size：存储单元宽度，8bit右击左侧地址值可改变地址和数据的显示格式；表中任意数据的地制值=列值+行值（图中蓝色单元的地址为32+3=35） 1.2 利用mif软件生成本次任务中我采用的是Guagle。优：方便导出mif文件，尤其是数据量比较大时。缺：此款软件可以自动设置的波形只有：方波、正弦波、锯齿波、三角波。不过这个软件支持手绘图形。使用方法： 更改设定波形和变量可以对相应参数进行配置。 1.3 利用高级语言C语言或matlab语言来生成相应的mif文件C语言生成正弦波的数据波形（代码来源于网络）123456789101112131415161718192021222324252627282930313233343536373839404142434445#include &lt;stdio.h&gt;#include &lt;math.h&gt;#define PI 3.141592#define DEPTH 128 /*数据深度，即存储单元的个数*/#define WIDTH 8 /*存储单元的宽度*/int main(void)&#123; int i,temp; float s; FILE *fp; fp = fopen(&quot;TestMif.mif&quot;,&quot;w&quot;); /*文件名随意，但扩展名必须为.mif*/ if(NULL==fp) printf(&quot;Can not creat file!
&quot;); else &#123; printf(&quot;File created successfully!
&quot;); /* * 生成文件头：注意不要忘了“;” */ fprintf(fp,&quot;DEPTH = %d;
&quot;,DEPTH); fprintf(fp,&quot;WIDTH = %d;
&quot;,WIDTH); fprintf(fp,&quot;ADDRESS_RADIX = HEX;
&quot;); fprintf(fp,&quot;DATA_RADIX = HEX;
&quot;); fprintf(fp,&quot;CONTENT
&quot;); fprintf(fp,&quot;BEGIN
&quot;); /* * 以十六进制输出地址和数据 */ for(i=0;i&lt;DEPTH;i++) &#123; /*周期为128个点的正弦波*/ s = sin(PI*i/64); /*将-1～1之间的正弦波的值扩展到0-255之间*/ temp = (int)((s+1)*255/2); /*以十六进制输出地址和数据*/ fprintf(fp,&quot;%x	:	%x;
&quot;,i,temp); &#125;//end for fprintf(fp,&quot;END;
&quot;); fclose(fp); &#125;&#125; matlab1234567891011121314151617depth = 512; %存储器的单元数widths = 8; %数据宽度为8位%N = 0:511;%s =round(127*sin(2*pi*N/512)+128); %计算0 ~2*pi之间的sinֵfidc = fopen(&apos;sin.mif&apos;,&apos;wt&apos;);fprintf(fidc , &apos;depth = %d;
&apos;,depth);fprintf(fidc, &apos;width = %d;
&apos;,widths);fprintf(fidc, &apos;address_radix = UNS;
&apos;);fprintf(fidc,&apos;data_radix = UNS;
&apos;);fprintf(fidc,&apos;content begin
&apos;);for(x = 1 : depth) fprintf(fidc,&apos;%d:%d;
&apos;,x-1,round(127*sin(2*pi*(x-1)/512)+128)); endfprintf(fidc, &apos;end;&apos;);fclose(fidc); matlab（代码来源于陈强胜）1234567891011121314151617181920%mif生成 xt为输入WIDTH=8;DEPTH=256xt2=floor(xt);%xt取整xt2=xt2+128.*ones(1,256);%将数据加128fp=fopen(&apos;sin.txt&apos;,&apos;w&apos;);fprintf(fp,&apos;WIDTH=%d;
&apos;,WIDTH);fprintf(fp,&apos;DEPTH=%d;
&apos;,DEPTH);fprintf(fp,&apos;ADDRESS_RADIX=UNS;
&apos;);fprintf(fp,&apos;DATA_RADIX=UNS;
&apos;);fprintf(fp,&apos;CONTENT BEGIN
&apos;);for i=0:DEPTH-1 fprintf(fp,&apos;%d : &apos;,i); fprintf(fp,&apos;%d;
&apos;,xt2(i+1));endfprintf(fp,&apos;END;
&apos;);fclose(fp); 二、定制ROM：PORT使用方法【Tool】_&gt;【MegaWizard Plug-In Manager】 bits和words根据mif文件的数据来设置 一直点Next（详情解释见《Hello FPGA》-软件工具篇第五章IP核之ROM）生成之后需要对以上模块进行例化 三、各个模块代码【key_module】接收按键状态，并通过按键不同的状态来对不同的flag进行赋值 【DA_data_module】根据按键不同的状态，来改变DA_data输出数据，以及频率。波形选择、改变幅值波形通过case语句，在wave_flag取不同的值时，分别输出不同的波形（由于按键个数的限制在此只用了两种波形）输出波形幅值的大小通过移位来改变。ROM数据输出 【seg_module】控制数码管动态显示 六个数码管，每个数码管可以显示0~9，8=4’b1000；四位，所以iData为6*4=24位 四、例化 五、DAC转化【8位R-2R电阻网络】无论从哪个位置断开，向内看阻抗均为R。输出阻抗固定为R等效电压源、等效电流源第一个$U_{out}= rac{U_{D0}}{2}$第二个$U_{out}= rac{U_{D0}}{4}+ rac{U_{D1}}{2}$…第八个$U_{out}= rac{U_{D0}}{2^8}+ rac{U_{D1}}{2^7}+ rac{U_{D2}}{2^6}+ rac{U_{D3}}{2^5}+ rac{U_{D4}}{2^4}+ rac{U_{D5}}{2^3}+ rac{U_{D6}}{2^2}+ rac{U_{D7}}{2^1}$所以输出电压有256种变化 六、实物展示
